'use client';

import { Avatar } from '@/components/ui/avatar';
import { AccessDenied } from '@/components/shared/access-denied';
import { useAuthStore } from '@/stores/auth-store';
import { hasPermission } from '@/lib/constants/roles';
import { MOCK_ACTIVITY_FEED } from '@/lib/mock/data';

export default function ActivityPage() {
  const role = useAuthStore((s) => s.role);

  if (!hasPermission(role, 'dashboard:view_team')) {
    return <AccessDenied message="Members and viewers cannot access the activity feed." />;
  }

  return (
    <div>
      <div className="mb-6">
        <h1 className="text-2xl font-black tracking-tight text-black">Activity Feed</h1>
        <p className="text-sm text-neutral-500">Recent activity across the organization</p>
      </div>

      <div className="space-y-0">
        {MOCK_ACTIVITY_FEED.map((item, index) => (
          <div
            key={item.id}
            className={`flex gap-4 py-4 ${index < MOCK_ACTIVITY_FEED.length - 1 ? 'border-b border-neutral-200' : ''}`}
          >
            <Avatar name={item.actor.full_name} src={item.actor.avatar_url} size="sm" />
            <div className="min-w-0 flex-1">
              <p className="text-sm text-black">
                <span className="font-bold">{item.actor.full_name}</span>{' '}
                {item.description}
              </p>
              <p className="mt-0.5 text-xs text-neutral-400">
                {new Date(item.created_at).toLocaleDateString('en-IN', {
                  month: 'short',
                  day: 'numeric',
                  hour: '2-digit',
                  minute: '2-digit',
                })}
              </p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
